SELECT tf.fb_id AS fbId, tf.selection_id AS selectionId, tf.teacher_id AS teacherId, u_t.real_name AS teacherName, tf.student_id, u_s.real_name AS studentName, u_s.student_no AS studentNo, CASE WHEN ps.is_custom_topic = 1 THEN ps.custom_topic_name ELSE pt.topic_name END AS topicName, tf.feedback_type AS feedbackType, tf.content, tf.status, tf.handler_id AS handlerId, u_h.real_name AS handlerName, tf.handle_comment AS handleComment, tf.handle_time AS handleTime, tf.academic_year AS academicYear, tf.create_time AS createTime FROM teacher_feedback tf LEFT JOIN sys_user u_t ON tf.teacher_id = u_t.user_id LEFT JOIN sys_user u_s ON tf.student_id = u_s.user_id LEFT JOIN project_selection ps ON tf.selection_id = ps.selection_id LEFT JOIN project_topic pt ON ps.topic_id = pt.topic_id LEFT JOIN sys_user u_h ON tf.handler_id = u_h.user_id
tf.is_deleted = 0
AND ps.campus_name LIKE CONCAT('%', #{campusName}, '%')
AND tf.academic_year = #{academicYear}
AND tf.feedback_type = #{feedbackType}
AND tf.status = #{status}
AND (u_t.real_name LIKE CONCAT('%', #{keyword}, '%') OR u_s.real_name LIKE CONCAT('%', #{keyword}, '%') OR u_s.student_no LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY tf.create_time DESC

SELECT tf.fb_id AS fbId, tf.selection_id AS selectionId, tf.teacher_id AS teacherId, u_t.real_name AS teacherName, tf.student_id, u_s.real_name AS studentName, u_s.student_no AS studentNo, CASE WHEN ps.is_custom_topic = 1 THEN ps.custom_topic_name ELSE pt.topic_name END AS topicName, tf.feedback_type AS feedbackType, tf.content, tf.status, tf.handler_id AS handlerId, u_h.real_name AS handlerName, tf.handle_comment AS handleComment, tf.handle_time AS handleTime, tf.academic_year AS academicYear, tf.create_time AS createTime FROM teacher_feedback tf LEFT JOIN sys_user u_t ON tf.teacher_id = u_t.user_id LEFT JOIN sys_user u_s ON tf.student_id = u_s.user_id LEFT JOIN project_selection ps ON tf.selection_id = ps.selection_id LEFT JOIN project_topic pt ON ps.topic_id = pt.topic_id LEFT JOIN sys_user u_h ON tf.handler_id = u_h.user_id
tf.is_deleted = 0 AND tf.teacher_id = #{teacherId}
AND tf.academic_year = #{academicYear}
AND tf.feedback_type = #{feedbackType}
AND tf.status = #{status}
ORDER BY tf.create_time DESC

SELECT COUNT(*) FROM teacher_feedback tf LEFT JOIN project_selection ps ON tf.selection_id = ps.selection_id LEFT JOIN sys_user u_t ON tf.teacher_id = u_t.user_id LEFT JOIN sys_user u_s ON tf.student_id = u_s.user_id
tf.is_deleted = 0
AND ps.campus_name LIKE CONCAT('%', #{campusName}, '%')
AND tf.academic_year = #{academicYear}
AND tf.feedback_type = #{feedbackType}
AND tf.status = #{status}
AND (u_t.real_name LIKE CONCAT('%', #{keyword}, '%') OR u_s.real_name LIKE CONCAT('%', #{keyword}, '%') OR u_s.student_no LIKE CONCAT('%', #{keyword}, '%'))

SELECT COUNT(*)
FROM teacher_feedback tf

    tf.is_deleted = 0
    AND tf.teacher_id = #{teacherId}

        AND tf.academic_year = #{academicYear}


        AND tf.feedback_type = #{feedbackType}


        AND tf.status = #{status}
